INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0307', 'S1.1', 1, 'single_choice', 'Nguyên tắc y đức cốt lõi "không gây hại cho người bệnh" được gọi là:', '["Tôn trọng tự chủ", "Không làm hại (non-maleficence)", "Công bằng", "Làm điều thiện (beneficence)"]'::jsonb, 1, 'Non-maleficence — "trước hết không gây hại" — là nguyên tắc y đức nền tảng, bắt buộc ĐD cân nhắc nguy cơ trước mỗi can thiệp.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0308', 'S1.1', 2, 'single_choice', 'Khi người bệnh từ chối một thủ thuật đã được giải thích đầy đủ, điều dưỡng nên:', '["Thực hiện vì lợi ích người bệnh", "Tôn trọng quyết định và ghi hồ sơ, báo bác sĩ", "Thuyết phục người nhà ép buộc", "Bỏ qua và chuyển bệnh nhân"]'::jsonb, 1, 'Nguyên tắc tôn trọng quyền tự chủ: người bệnh có năng lực có quyền từ chối; ĐD ghi nhận, báo bác sĩ và tiếp tục chăm sóc an toàn.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0309', 'S1.1', 1, 'single_choice', 'Bảo mật thông tin người bệnh thuộc phạm trù đạo đức nào?', '["Trung thực", "Bảo mật và tôn trọng riêng tư", "Công bằng", "Tận tụy"]'::jsonb, 1, 'Giữ bí mật thông tin sức khỏe là nghĩa vụ đạo đức và pháp lý của ĐD, chỉ chia sẻ khi có cơ sở chuyên môn/pháp luật.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0310', 'S1.1', 2, 'single_choice', 'Hành vi nào sau đây VI PHẠM chuẩn đạo đức nghề nghiệp điều dưỡng?', '["Giải thích trước khi làm thủ thuật", "Nhận quà có điều kiện để ưu tiên người bệnh", "Báo cáo sự cố y khoa", "Rửa tay trước khi chăm sóc"]'::jsonb, 1, 'Nhận lợi ích để thiên vị làm tổn hại tính công bằng và liêm chính nghề nghiệp — vi phạm chuẩn đạo đức.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0311', 'S1.1', 3, 'single_choice', 'Khi phát hiện đồng nghiệp thực hiện sai kỹ thuật gây nguy cơ cho người bệnh, ứng xử phù hợp nhất là:', '["Im lặng để giữ hòa khí", "Can thiệp bảo đảm an toàn NB rồi trao đổi/báo cáo theo quy trình", "Chỉ trích công khai trước NB", "Ghi âm để tố cáo"]'::jsonb, 1, 'Ưu tiên an toàn người bệnh, sau đó góp ý xây dựng và báo cáo theo kênh chuyên môn — cân bằng giữa bảo vệ NB và tôn trọng đồng nghiệp.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0312', 'S1.1', 2, 'single_choice', '"Đồng cảm nghề nghiệp" trong chăm sóc điều dưỡng nghĩa là:', '["Đồng nhất cảm xúc, mất khách quan", "Thấu hiểu cảm xúc NB nhưng giữ được sự chuyên nghiệp và ranh giới", "Thương hại người bệnh", "Tránh tiếp xúc cảm xúc"]'::jsonb, 1, 'Đồng cảm nghề nghiệp là thấu hiểu và đáp ứng nhu cầu cảm xúc NB trong khi vẫn giữ ranh giới và khách quan chuyên môn.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0313', 'S1.2', 2, 'single_choice', 'Theo Thông tư 32/2023/TT-BYT, chứng chỉ/giấy phép hành nghề điều dưỡng gắn với:', '["Bằng cấp học vấn", "Phạm vi hành nghề được cấp phép", "Thâm niên công tác", "Vị trí việc làm"]'::jsonb, 1, 'TT32 quy định hành nghề khám chữa bệnh theo phạm vi hành nghề được cấp phép, không được vượt phạm vi chuyên môn.', '', ARRAY['VB01','VB02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0314', 'S1.2', 1, 'single_choice', 'Điều dưỡng KHÔNG được phép làm điều nào dưới đây?', '["Theo dõi dấu hiệu sinh tồn", "Ra y lệnh chẩn đoán và kê đơn thuốc độc lập", "Thực hiện y lệnh của bác sĩ", "Chăm sóc vết thương"]'::jsonb, 1, 'Chẩn đoán bệnh và kê đơn thuộc phạm vi bác sĩ; ĐD thực hiện chăm sóc và y lệnh trong phạm vi được cấp phép.', '', ARRAY['VB01','VB02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0315', 'S1.2', 2, 'single_choice', 'Khi y lệnh của bác sĩ có dấu hiệu bất thường/nguy cơ sai sót, điều dưỡng phải:', '["Thực hiện ngay vì là y lệnh", "Hỏi lại/xác minh với bác sĩ trước khi thực hiện", "Tự ý sửa y lệnh", "Từ chối chăm sóc"]'::jsonb, 1, 'ĐD có trách nhiệm kiểm tra y lệnh; khi nghi ngờ phải xác minh lại với người ra y lệnh để bảo đảm an toàn NB.', '', ARRAY['VB01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0316', 'S1.2', 3, 'single_choice', 'Nguyên tắc "hành nghề trong phạm vi được cấp phép" nhằm mục đích chính:', '["Giảm nhân sự", "Bảo đảm an toàn người bệnh và trách nhiệm pháp lý rõ ràng", "Tăng thu nhập", "Phân cấp hành chính"]'::jsonb, 1, 'Giới hạn phạm vi hành nghề bảo đảm mỗi can thiệp do người đủ năng lực thực hiện, giảm rủi ro và xác định trách nhiệm.', '', ARRAY['VB01','VB02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0317', 'S1.2', 1, 'single_choice', 'Cập nhật kiến thức y khoa liên tục (CME/CPD) đối với điều dưỡng là:', '["Tự nguyện hoàn toàn", "Yêu cầu bắt buộc để duy trì năng lực và giấy phép hành nghề", "Chỉ dành cho bác sĩ", "Không cần thiết nếu đã có bằng"]'::jsonb, 1, 'Đào tạo liên tục là bắt buộc để duy trì và cập nhật năng lực hành nghề theo quy định.', '', ARRAY['VB01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0318', 'S1.2', 2, 'single_choice', 'Người bệnh có quyền được biết thông tin nào trước khi đồng ý một thủ thuật?', '["Chỉ tên thủ thuật", "Mục đích, lợi ích, nguy cơ và lựa chọn thay thế", "Chỉ chi phí", "Không cần thông tin"]'::jsonb, 1, 'Đồng thuận có hiểu biết (informed consent) đòi hỏi giải thích mục đích, lợi ích, nguy cơ và các lựa chọn thay thế.', '', ARRAY['VB01','VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0319', 'S1.3', 2, 'single_choice', 'Khoa Phẫu thuật - Gây mê hồi sức thường được tổ chức gồm các bộ phận chính nào?', '["Chỉ phòng mổ", "Phòng mổ, hồi tỉnh và đơn vị gây mê hồi sức", "Chỉ hồi sức", "Phòng khám ngoại trú"]'::jsonb, 1, 'Khoa PTGMHS gồm khu phẫu thuật (phòng mổ), phòng hồi tỉnh (PACU) và bộ phận gây mê hồi sức.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0320', 'S1.3', 1, 'single_choice', 'Nguyên tắc phân luồng một chiều trong khu phẫu thuật nhằm:', '["Tiết kiệm diện tích", "Kiểm soát nhiễm khuẩn, tách luồng sạch - bẩn", "Tăng tốc độ mổ", "Giảm nhân lực"]'::jsonb, 1, 'Phân luồng một chiều (sạch sang bẩn) hạn chế lây nhiễm chéo trong khu phẫu thuật.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0321', 'S1.3', 2, 'single_choice', 'Khu vực nào trong khu phẫu thuật yêu cầu mức vô khuẩn cao nhất?', '["Hành lang tiếp nhận", "Buồng mổ (khu vô khuẩn)", "Phòng thay đồ", "Khu hành chính"]'::jsonb, 1, 'Buồng mổ là khu vô khuẩn, yêu cầu kiểm soát không khí, trang phục và quy trình chặt chẽ nhất.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0322', 'S1.3', 1, 'single_choice', 'Trước khi vào khu phẫu thuật, nhân viên phải:', '["Giữ nguyên trang phục thường", "Thay trang phục phòng mổ, đội mũ, mang khẩu trang", "Chỉ rửa tay", "Không cần chuẩn bị"]'::jsonb, 1, 'Thay trang phục chuyên dụng, đội mũ trùm tóc và mang khẩu trang là yêu cầu bắt buộc để vào khu phẫu thuật.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0323', 'S1.3', 2, 'single_choice', 'Việc kiểm kê dụng cụ - gạc trước và sau mổ nhằm:', '["Đánh giá năng suất", "Phòng ngừa để quên dị vật trong cơ thể NB", "Tính chi phí", "Bàn giao ca"]'::jsonb, 1, 'Đếm dụng cụ, kim, gạc trước/sau mổ là hàng rào an toàn ngăn sót dị vật — một sự cố nghiêm trọng.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0324', 'S1.3', 3, 'single_choice', 'Trách nhiệm quản lý chuyên môn buồng mổ về vô khuẩn và an toàn thuộc về:', '["Chỉ phẫu thuật viên", "Cả kíp mổ theo phân công, ĐD vòng ngoài điều phối và giám sát", "Chỉ người bệnh", "Phòng hành chính"]'::jsonb, 1, 'An toàn buồng mổ là trách nhiệm chung của kíp mổ; ĐD vòng ngoài điều phối, giám sát vô khuẩn và đếm dụng cụ.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0325', 'S2.1', 1, 'single_choice', 'Mục đích chính của việc nhịn ăn uống trước gây mê là:', '["Giảm cân trước mổ", "Giảm nguy cơ trào ngược và hít sặc khi khởi mê", "Tiết kiệm chi phí", "Giảm đau"]'::jsonb, 1, 'Nhịn ăn giúp làm rỗng dạ dày, giảm nguy cơ trào ngược - hít sặc dịch vị khi mất phản xạ bảo vệ đường thở lúc khởi mê.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0326', 'S2.1', 2, 'single_choice', 'Theo hướng dẫn nhịn ăn trước mổ chương trình cho người lớn, thời gian nhịn dịch trong (nước lọc) thường là:', '["1 giờ", "2 giờ", "8 giờ", "12 giờ"]'::jsonb, 1, 'Hướng dẫn hiện đại (ASA) cho phép uống dịch trong đến 2 giờ trước mổ chương trình, giúp NB dễ chịu hơn mà vẫn an toàn.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0327', 'S2.1', 2, 'single_choice', 'Bảng kiểm an toàn phẫu thuật của WHO gồm mấy thời điểm chính?', '["1 (trước mổ)", "3 (Sign in - Time out - Sign out)", "5", "2"]'::jsonb, 1, 'Checklist WHO gồm 3 thời điểm: trước khởi mê (Sign in), trước rạch da (Time out), trước khi NB rời phòng mổ (Sign out).', '', ARRAY['CS01','VB10'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0328', 'S2.1', 1, 'single_choice', 'Trước mổ, việc xác nhận đúng người bệnh - đúng vị trí - đúng thủ thuật nhằm phòng ngừa:', '["Nhiễm khuẩn", "Sai sót mổ nhầm người/vị trí/thủ thuật", "Mất máu", "Đau sau mổ"]'::jsonb, 1, 'Xác nhận "3 đúng" ở bước Time out phòng ngừa sự cố mổ nhầm người/vị trí/thủ thuật.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0329', 'S2.1', 2, 'single_choice', 'Chuẩn bị vùng mổ (loại bỏ lông) nếu cần nên thực hiện:', '["Bằng dao cạo nhiều giờ trước", "Ngay trước mổ, dùng tông đơ (clipper), tránh dao cạo", "Không bao giờ loại bỏ lông", "Tự NB làm tại nhà tùy ý"]'::jsonb, 1, 'Nên dùng tông đơ ngay trước mổ; dao cạo gây vi tổn thương da làm tăng nguy cơ nhiễm khuẩn vết mổ.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0330', 'S2.1', 3, 'single_choice', 'Người bệnh đái tháo đường chuẩn bị mổ chương trình, kiểm soát đường huyết chu phẫu nhằm:', '["Tăng đường huyết để có năng lượng", "Duy trì đường huyết mục tiêu, giảm nguy cơ nhiễm khuẩn và biến chứng", "Nhịn hoàn toàn insulin", "Không cần theo dõi"]'::jsonb, 1, 'Kiểm soát đường huyết chu phẫu ở mức mục tiêu làm giảm nhiễm khuẩn vết mổ và biến chứng lành thương.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0331', 'S2.1', 1, 'single_choice', 'Đánh giá đường thở trước gây mê (ví dụ phân độ Mallampati) nhằm:', '["Đánh giá tim mạch", "Dự báo khó khăn khi đặt nội khí quản", "Đo chức năng thận", "Đánh giá dinh dưỡng"]'::jsonb, 1, 'Đánh giá đường thở (Mallampati, há miệng, cổ...) giúp tiên lượng đặt NKQ khó và chuẩn bị phương án dự phòng.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0332', 'S2.1', 2, 'single_choice', 'Hồ sơ bệnh án trước mổ bắt buộc phải có yếu tố nào sau đây?', '["Chỉ tên tuổi", "Giấy cam kết/đồng thuận phẫu thuật đã ký", "Hóa đơn viện phí", "Ảnh chân dung"]'::jsonb, 1, 'Bản đồng thuận phẫu thuật đã được giải thích và ký là bắt buộc trong hồ sơ trước mổ.', '', ARRAY['CS01','VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0333', 'S2.1', 2, 'single_choice', 'Tháo bỏ tư trang, răng giả, kính áp tròng trước khi vào phòng mổ nhằm:', '["Tránh mất mát tài sản đơn thuần", "Bảo đảm an toàn (tránh dị vật, bỏng điện, tổn thương) và tránh thất lạc", "Thẩm mỹ", "Giảm cân"]'::jsonb, 1, 'Tháo trang sức kim loại tránh bỏng khi dùng dao điện, tháo răng giả tránh rơi vào đường thở; đồng thời tránh thất lạc.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0334', 'S2.1', 1, 'single_choice', 'Việc kiểm tra tiền sử dị ứng thuốc trước mổ là:', '["Không cần thiết", "Bắt buộc để phòng ngừa phản vệ và chọn thuốc an toàn", "Chỉ với trẻ em", "Chỉ khi NB yêu cầu"]'::jsonb, 1, 'Khai thác tiền sử dị ứng (thuốc, latex...) là bắt buộc để phòng ngừa phản vệ trong gây mê - phẫu thuật.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0335', 'S2.2', 1, 'single_choice', 'Ưu tiên số một khi tiếp nhận người bệnh tại phòng hồi tỉnh là:', '["Đánh giá đau", "Đánh giá đường thở - hô hấp - tuần hoàn (ABC)", "Ghi hồ sơ", "Cho ăn"]'::jsonb, 1, 'Theo dõi sau mổ luôn ưu tiên đường thở, hô hấp, tuần hoàn (ABC) vì biến chứng sớm thường liên quan đường thở/hô hấp.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0336', 'S2.2', 2, 'single_choice', 'Thang điểm Aldrete dùng để:', '["Đánh giá đau", "Đánh giá mức hồi phục để cho NB rời phòng hồi tỉnh", "Đánh giá dinh dưỡng", "Phân loại vết mổ"]'::jsonb, 1, 'Thang Aldrete đánh giá vận động, hô hấp, tuần hoàn, tri giác, SpO2 để quyết định cho NB xuất phòng hồi tỉnh.', '', ARRAY['CS03','CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0337', 'S2.2', 2, 'single_choice', 'Dấu hiệu sớm gợi ý chảy máu trong sau mổ là:', '["Mạch chậm, huyết áp tăng", "Mạch nhanh, huyết áp tụt, da niêm nhợt", "Sốt cao", "Tiểu nhiều"]'::jsonb, 1, 'Chảy máu/giảm thể tích tuần hoàn biểu hiện mạch nhanh, tụt huyết áp, da niêm nhợt, dẫn lưu ra máu đỏ tươi tăng.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0338', 'S2.2', 1, 'single_choice', 'Tư thế phù hợp cho người bệnh sau mổ còn lơ mơ, chưa tỉnh hẳn (nguy cơ nôn) là:', '["Nằm ngửa đầu bằng", "Nằm nghiêng an toàn, đầu nghiêng một bên", "Ngồi thẳng", "Nằm sấp"]'::jsonb, 1, 'Tư thế nghiêng an toàn giúp dịch nôn thoát ra ngoài, tránh hít sặc khi NB chưa tỉnh và phản xạ bảo vệ chưa hồi phục.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0339', 'S2.2', 2, 'single_choice', 'Buồn nôn và nôn sau mổ (PONV) nên được:', '["Bỏ qua vì tự hết", "Đánh giá nguy cơ và dự phòng/điều trị bằng thuốc chống nôn theo y lệnh", "Cho ăn ngay", "Truyền thật nhiều dịch"]'::jsonb, 1, 'PONV cần đánh giá nguy cơ và xử trí bằng thuốc chống nôn; nôn nhiều gây khó chịu, mất nước và nguy cơ hít sặc.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0340', 'S2.2', 3, 'single_choice', 'Người bệnh sau mổ SpO2 tụt còn 88%, thở nông, gọi hỏi đáp ứng chậm. Xử trí đầu tiên của điều dưỡng:', '["Cho uống nước", "Khai thông đường thở, cho thở oxy và gọi bác sĩ", "Đo đường huyết", "Thay băng vết mổ"]'::jsonb, 1, 'Giảm SpO2 kèm tri giác giảm ưu tiên khai thông đường thở, cung cấp oxy và báo bác sĩ ngay — xử trí theo ABC.', '', ARRAY['CS03','CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0341', 'S2.2', 1, 'single_choice', 'Theo dõi dẫn lưu sau mổ cần ghi nhận:', '["Chỉ màu sắc", "Số lượng, màu sắc, tính chất dịch và tình trạng ống", "Chỉ số lượng", "Không cần ghi"]'::jsonb, 1, 'Ghi đầy đủ số lượng, màu sắc, tính chất dịch dẫn lưu và độ thông của ống giúp phát hiện sớm biến chứng.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0342', 'S2.2', 2, 'single_choice', 'Mục tiêu vận động sớm sau mổ (early mobilization) là:', '["Giảm chi phí", "Giảm biến chứng huyết khối, viêm phổi và tắc ruột, hồi phục nhanh", "Tăng đau", "Rút ngắn gây mê"]'::jsonb, 1, 'Vận động sớm làm giảm huyết khối tĩnh mạch, viêm phổi ứ đọng, liệt ruột và thúc đẩy hồi phục.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0343', 'S2.2', 2, 'single_choice', 'Theo dõi nước tiểu sau mổ, thiểu niệu ở người lớn thường được định nghĩa khi lượng nước tiểu:', '["< 0,5 ml/kg/giờ", "> 2 ml/kg/giờ", "1-2 ml/kg/giờ", "Bằng 100 ml/giờ"]'::jsonb, 0, 'Thiểu niệu (< 0,5 ml/kg/giờ) gợi ý giảm tưới máu thận do thiếu dịch/tụt huyết áp, cần đánh giá và xử trí.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0344', 'S2.3', 2, 'single_choice', 'Biến chứng hô hấp thường gặp và nguy hiểm nhất tại phòng hồi tỉnh là:', '["Sốt", "Tắc nghẽn đường thở / giảm thông khí", "Táo bón", "Ngứa"]'::jsonb, 1, 'Tắc nghẽn đường thở (tụt lưỡi, co thắt thanh quản) và giảm thông khí do tồn dư thuốc là biến chứng nguy hiểm hàng đầu ở PACU.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0345', 'S2.3', 1, 'single_choice', 'Run lạnh (shivering) sau gây mê nên được xử trí bằng:', '["Để tự hết", "Ủ ấm, sưởi ấm và theo dõi, dùng thuốc theo y lệnh", "Chườm lạnh", "Cho vận động mạnh"]'::jsonb, 1, 'Ủ ấm chủ động giúp giảm run, giảm tiêu thụ oxy; run lạnh làm tăng nhu cầu oxy và khó chịu.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0346', 'S2.3', 3, 'single_choice', 'Người bệnh hồi tỉnh xuất hiện thở rít, co kéo, SpO2 tụt nhanh sau rút NKQ — nghĩ đến:', '["Đau vết mổ", "Co thắt thanh quản (laryngospasm)", "Táo bón", "Hạ đường huyết"]'::jsonb, 1, 'Co thắt thanh quản gây tắc nghẽn đường thở cấp; cần oxy áp lực dương, gọi hỗ trợ và xử trí theo phác đồ ngay.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0347', 'S2.3', 2, 'single_choice', 'Tiêu chuẩn KHÔNG phù hợp để cho người bệnh rời phòng hồi tỉnh là:', '["Tỉnh táo, tự bảo vệ đường thở", "Còn tụt SpO2, huyết động chưa ổn định", "Đau kiểm soát tốt", "Dấu hiệu sinh tồn ổn định"]'::jsonb, 1, 'NB chỉ được xuất PACU khi hô hấp - tuần hoàn ổn định; SpO2 thấp hoặc huyết động chưa ổn là chống chỉ định.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0348', 'S2.3', 1, 'single_choice', 'Theo dõi tri giác sau gây mê thường dựa trên:', '["Chỉ nhiệt độ", "Mức độ tỉnh, đáp ứng gọi hỏi và định hướng", "Cân nặng", "Nhóm máu"]'::jsonb, 1, 'Đánh giá tri giác dựa trên mức tỉnh, đáp ứng gọi/hỏi và định hướng để phát hiện tồn dư thuốc mê/an thần.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0349', 'S2.3', 2, 'single_choice', 'Tụt huyết áp tại phòng hồi tỉnh, nguyên nhân thường gặp cần loại trừ đầu tiên:', '["Đau", "Giảm thể tích tuần hoàn (mất máu/thiếu dịch)", "Lo âu", "Buồn nôn"]'::jsonb, 1, 'Tụt huyết áp sau mổ thường do giảm thể tích; cần đánh giá mất máu, bù dịch và tìm nguyên nhân trước khi dùng vận mạch.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0350', 'S2.3', 3, 'single_choice', 'Đau sau mổ nếu không kiểm soát tốt có thể gây hậu quả nào sau đây?', '["Không ảnh hưởng", "Tăng nhịp tim, huyết áp, giảm thông khí do thở nông, chậm hồi phục", "Hạ thân nhiệt duy nhất", "Tăng tiểu tiện"]'::jsonb, 1, 'Đau cấp gây đáp ứng stress (tim mạch), làm NB thở nông - hạn chế ho khạc, tăng biến chứng hô hấp và chậm hồi phục.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0351', 'S2.4', 2, 'single_choice', 'Biện pháp quan trọng trong "gói" phòng viêm phổi liên quan thở máy (VAP) là:', '["Nằm đầu bằng", "Nâng đầu giường 30-45 độ", "Không hút đàm", "Ngừng vệ sinh răng miệng"]'::jsonb, 1, 'Nâng đầu giường 30-45 độ giảm trào ngược và hít dịch — thành phần cốt lõi của gói dự phòng VAP.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0352', 'S2.4', 1, 'single_choice', 'SpO2 mục tiêu thông thường ở đa số người bệnh thở máy (không bệnh phổi mạn) là:', '["80-85%", "94-98%", "100% liên tục", "Dưới 90%"]'::jsonb, 1, 'Mục tiêu SpO2 94-98% cho hầu hết NB; tránh cả thiếu oxy lẫn tăng oxy máu quá mức.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0353', 'S2.4', 2, 'single_choice', 'Chăm sóc răng miệng bằng dung dịch sát khuẩn ở NB thở máy nhằm:', '["Thẩm mỹ", "Giảm vi khuẩn khoang miệng, dự phòng VAP", "Tăng tiết nước bọt", "Giảm đau"]'::jsonb, 1, 'Vệ sinh răng miệng bằng chlorhexidine giảm quần thể vi khuẩn khoang miệng, góp phần dự phòng VAP.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0354', 'S2.4', 3, 'single_choice', 'Áp lực bóng chèn (cuff) ống nội khí quản nên duy trì trong khoảng:', '["0-10 cmH2O", "20-30 cmH2O", "40-50 cmH2O", "Càng cao càng tốt"]'::jsonb, 1, 'Cuff 20-30 cmH2O đủ kín để giảm rò và hít, đồng thời tránh thiếu máu niêm mạc khí quản do áp lực quá cao.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0355', 'S2.4', 2, 'single_choice', 'Khi hút đàm nội khí quản, thời gian mỗi lần hút nên:', '["Không quá 10-15 giây", "Kéo dài 60 giây", "Bao lâu cũng được", "Chỉ 1 giây"]'::jsonb, 0, 'Mỗi lần hút không quá 10-15 giây để tránh thiếu oxy và rối loạn nhịp; nên tăng oxy trước và sau hút.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0356', 'S2.4', 1, 'single_choice', 'Báo động máy thở "áp lực đường thở cao" có thể do:', '["Hở hệ thống", "Tắc/gập ống, đàm nhiều, co thắt phế quản", "Hết pin", "Đủ oxy"]'::jsonb, 1, 'Áp lực cao thường do cản trở dòng khí: gập/tắc ống, tăng tiết đàm, co thắt phế quản — cần kiểm tra và xử trí.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0357', 'S2.4', 2, 'single_choice', 'Đánh giá sẵn sàng cai máy thở (weaning) dựa vào yếu tố nào?', '["Chỉ SpO2", "Nguyên nhân suy hô hấp cải thiện, huyết động ổn, tự thở tốt, oxy hóa đạt", "Cân nặng", "Nhóm máu"]'::jsonb, 1, 'Cai máy khi bệnh nền cải thiện, huyết động ổn, oxy hóa đạt và NB có khả năng tự thở hiệu quả.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0358', 'S2.5', 1, 'single_choice', 'Công cụ chuẩn hóa bàn giao người bệnh thường dùng là:', '["SOAP", "SBAR (Situation-Background-Assessment-Recommendation)", "ABCDE", "FAST"]'::jsonb, 1, 'SBAR chuẩn hóa nội dung bàn giao: Tình huống - Bối cảnh - Đánh giá - Khuyến nghị, giúp truyền đạt đủ và rõ.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0359', 'S2.5', 2, 'single_choice', 'Mục tiêu chính của bàn giao ca trực điều dưỡng là:', '["Hoàn tất giấy tờ", "Bảo đảm liên tục và an toàn chăm sóc, không bỏ sót thông tin", "Rút ngắn thời gian", "Đánh giá thi đua"]'::jsonb, 1, 'Bàn giao bảo đảm tính liên tục của chăm sóc, chuyển giao đầy đủ tình trạng NB và việc cần theo dõi/thực hiện.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0360', 'S2.5', 1, 'single_choice', 'Trong bàn giao, thông tin nào KHÔNG thể thiếu về mỗi người bệnh nặng?', '["Sở thích ăn uống", "Chẩn đoán, tình trạng hiện tại, y lệnh và việc cần theo dõi", "Quê quán", "Sở thích cá nhân"]'::jsonb, 1, 'Bàn giao NB nặng cần nêu chẩn đoán, diễn tiến, y lệnh đang thực hiện và các điểm cần theo dõi/cảnh báo.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0361', 'S2.5', 2, 'single_choice', 'Bàn giao tại giường (bedside handover) có ưu điểm:', '["Nhanh hơn giấy tờ", "Cùng quan sát, xác nhận trực tiếp tình trạng NB và tăng an toàn", "Không cần ghi chép", "NB không tham gia"]'::jsonb, 1, 'Bàn giao tại giường cho phép hai ĐD cùng quan sát, kiểm chứng thông tin và NB tham gia, giảm sai sót.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0362', 'S2.5', 3, 'single_choice', 'Sự cố do "mất thông tin khi chuyển giao" được xếp vào nhóm nguy cơ an toàn nào?', '["Nhiễm khuẩn", "Lỗi giao tiếp/chuyển giao (communication/handoff)", "Té ngã", "Loét tì đè"]'::jsonb, 1, 'Chuyển giao kém là nguyên nhân hàng đầu của sự cố y khoa; chuẩn hóa (SBAR, bedside) giúp giảm rủi ro.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0363', 'S2.5', 1, 'single_choice', 'Việc ghi chép hồ sơ điều dưỡng cần bảo đảm nguyên tắc:', '["Ghi sau khi hết ca cho gọn", "Kịp thời, chính xác, trung thực và đầy đủ", "Chỉ ghi việc tốt", "Ghi bằng bút chì"]'::jsonb, 1, 'Hồ sơ phải kịp thời, chính xác, trung thực, đầy đủ — là bằng chứng chăm sóc và cơ sở pháp lý.', '', ARRAY['CS05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0364', 'S2.6', 2, 'single_choice', 'Nguyên tắc dinh dưỡng ưu tiên cho NB phẫu thuật có đường tiêu hóa hoạt động là:', '["Nuôi tĩnh mạch hoàn toàn", "Ưu tiên nuôi ăn đường tiêu hóa (enteral) khi có thể", "Nhịn kéo dài", "Chỉ truyền dịch"]'::jsonb, 1, 'Khi ruột hoạt động, ưu tiên nuôi ăn đường tiêu hóa vì duy trì hàng rào ruột, giảm nhiễm khuẩn và biến chứng so với nuôi tĩnh mạch.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0365', 'S2.6', 1, 'single_choice', 'Suy dinh dưỡng trước mổ ảnh hưởng thế nào đến kết quả phẫu thuật?', '["Không ảnh hưởng", "Tăng nguy cơ nhiễm khuẩn, chậm lành vết mổ, kéo dài nằm viện", "Giảm đau", "Rút ngắn hồi phục"]'::jsonb, 1, 'Suy dinh dưỡng làm suy giảm miễn dịch và lành thương, tăng biến chứng và thời gian nằm viện.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0366', 'S2.6', 2, 'single_choice', 'Người bệnh ung thư phẫu thuật thường cần chú ý dinh dưỡng vì:', '["Luôn thừa cân", "Tăng dị hóa, chán ăn, nguy cơ suy mòn (cachexia)", "Không cần protein", "Chỉ cần truyền đường"]'::jsonb, 1, 'Bệnh nhân ung thư có tăng chuyển hóa dị hóa và chán ăn dẫn tới suy mòn, cần đánh giá và can thiệp dinh dưỡng sớm.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0367', 'S2.6', 1, 'single_choice', 'Đánh giá nguy cơ dinh dưỡng khi nhập viện nên dùng công cụ như:', '["Glasgow", "MUST/NRS-2002", "Aldrete", "Mallampati"]'::jsonb, 1, 'MUST hoặc NRS-2002 là công cụ sàng lọc nguy cơ dinh dưỡng phổ biến để phát hiện NB cần can thiệp.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0368', 'S2.6', 3, 'single_choice', '"Hội chứng nuôi ăn lại" (refeeding syndrome) nguy hiểm vì gây:', '["Tăng cân nhanh có lợi", "Rối loạn điện giải nặng (hạ phospho, kali, magie) đe dọa tính mạng", "Táo bón", "Tăng đường huyết đơn thuần"]'::jsonb, 1, 'Refeeding gây dịch chuyển điện giải nội bào, đặc biệt hạ phosphate, kali, magie — có thể gây loạn nhịp và tử vong; cần nuôi ăn lại từ từ.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0369', 'S2.6', 2, 'single_choice', 'Chế độ ăn sau mổ đường tiêu hóa thường tiến triển theo trình tự:', '["Ăn đặc ngay", "Từ lỏng/loãng tăng dần theo dung nạp và nhu động ruột", "Nhịn 7 ngày", "Chỉ ăn qua tĩnh mạch"]'::jsonb, 1, 'Sau mổ tiêu hóa, cho ăn tiến triển từ dịch trong/lỏng, tăng dần khi có nhu động và dung nạp tốt (ERAS khuyến khích ăn sớm).', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0370', 'S3.1', 1, 'single_choice', 'Người nhóm máu O có kháng thể tự nhiên nào trong huyết thanh?', '["Không có kháng thể", "Kháng A và kháng B", "Chỉ kháng A", "Chỉ kháng B"]'::jsonb, 1, 'Nhóm O không có kháng nguyên A/B trên hồng cầu nhưng có cả kháng thể kháng A và kháng B trong huyết thanh.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0371', 'S3.1', 1, 'single_choice', 'Người nhóm máu AB có đặc điểm kháng nguyên/kháng thể:', '["Có kháng A và kháng B", "Có kháng nguyên A và B, không có kháng thể kháng A/B", "Chỉ kháng nguyên A", "Không có kháng nguyên"]'::jsonb, 1, 'Nhóm AB mang cả kháng nguyên A và B trên hồng cầu, huyết thanh không có kháng thể kháng A/B (nhận máu phổ thông).', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0372', 'S3.1', 2, 'single_choice', 'Định nhóm ABO bằng phương pháp huyết thanh mẫu (dùng anti-A, anti-B) là:', '["Phương pháp huyết thanh mẫu (forward typing)", "Phương pháp hồng cầu mẫu (reverse typing)", "Nghiệm pháp Coombs", "Phản ứng chéo"]'::jsonb, 0, 'Dùng huyết thanh mẫu anti-A/anti-B để xác định kháng nguyên trên hồng cầu người bệnh là định nhóm thuận (forward typing).', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0373', 'S3.1', 3, 'single_choice', 'Nguyên tắc bắt buộc để bảo đảm định nhóm ABO chính xác tại giường trước truyền máu là:', '["Chỉ định nhóm một lần từ trước", "Định nhóm tại giường và đối chiếu ngay trước truyền cho đúng NB, đúng đơn vị máu", "Bỏ qua nếu đã có kết quả xét nghiệm", "Chỉ cần nhóm Rh"]'::jsonb, 1, 'Phản ứng tan máu do truyền nhầm nhóm ABO thường do lỗi định danh; bắt buộc định nhóm tại giường và đối chiếu NB - đơn vị máu ngay trước truyền.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0374', 'S3.1', 2, 'single_choice', 'Hiện tượng ngưng kết khi trộn hồng cầu người bệnh với anti-A nghĩa là:', '["Không có kháng nguyên A", "Hồng cầu mang kháng nguyên A", "Nhóm O", "Nhóm máu hiếm"]'::jsonb, 1, 'Ngưng kết với anti-A chứng tỏ hồng cầu có kháng nguyên A (nhóm A hoặc AB).', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0375', 'S3.1', 1, 'single_choice', 'Người cho máu toàn phần "phổ thông" (universal donor) về ABO là nhóm:', '["AB", "O", "A", "B"]'::jsonb, 1, 'Nhóm O (hồng cầu không có kháng nguyên A/B) là người cho hồng cầu phổ thông; AB là người nhận phổ thông.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0376', 'S3.1', 2, 'single_choice', 'Trước khi truyền máu, xét nghiệm hòa hợp (phản ứng chéo) nhằm:', '["Xác định nhóm Rh", "Phát hiện bất tương hợp giữa máu người cho và huyết thanh người nhận", "Đo hemoglobin", "Đếm tiểu cầu"]'::jsonb, 1, 'Phản ứng chéo (crossmatch) kiểm tra sự tương hợp giữa hồng cầu người cho và huyết thanh người nhận để tránh tan máu.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0377', 'S3.1', 3, 'single_choice', 'Nếu định nhóm thuận và định nhóm nghịch cho kết quả không phù hợp nhau, xử trí đúng là:', '["Chọn kết quả định nhóm thuận", "Không kết luận, làm lại và tìm nguyên nhân trước khi truyền", "Chọn nhóm O truyền ngay", "Bỏ qua định nhóm nghịch"]'::jsonb, 1, 'Bất đồng giữa forward và reverse typing là dấu hiệu cảnh báo; phải làm lại, tìm nguyên nhân, tuyệt đối không truyền khi chưa xác định chắc chắn.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0378', 'S3.2', 1, 'single_choice', 'Khối hồng cầu (packed red cells) được chỉ định chủ yếu để:', '["Bù đông máu", "Nâng khả năng vận chuyển oxy (thiếu máu/mất máu)", "Bù tiểu cầu", "Bù thể tích đơn thuần"]'::jsonb, 1, 'Khối hồng cầu dùng để tăng vận chuyển oxy ở NB thiếu máu hoặc mất máu, không dùng chỉ để bù thể tích.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0379', 'S3.2', 2, 'single_choice', 'Huyết tương tươi đông lạnh (FFP) được chỉ định khi:', '["Thiếu máu đơn thuần", "Thiếu nhiều yếu tố đông máu / rối loạn đông máu", "Giảm tiểu cầu đơn thuần", "Tăng kali"]'::jsonb, 1, 'FFP cung cấp các yếu tố đông máu, dùng khi thiếu hụt nhiều yếu tố (chảy máu do rối loạn đông máu, quá liều kháng vitamin K...).', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0380', 'S3.2', 2, 'single_choice', 'Khối tiểu cầu được chỉ định trong trường hợp:', '["Thiếu yếu tố VIII", "Giảm tiểu cầu nặng có chảy máu hoặc dự phòng chảy máu", "Thiếu máu", "Tăng đông"]'::jsonb, 1, 'Khối tiểu cầu dùng cho NB giảm tiểu cầu nặng kèm chảy máu hoặc trước thủ thuật có nguy cơ chảy máu.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0381', 'S3.2', 3, 'single_choice', 'Tủa lạnh (cryoprecipitate) giàu thành phần nào?', '["Albumin", "Fibrinogen, yếu tố VIII, yếu tố XIII, von Willebrand", "Hồng cầu", "Bạch cầu"]'::jsonb, 1, 'Tủa lạnh giàu fibrinogen, yếu tố VIII, XIII và vWF; dùng khi giảm fibrinogen máu hoặc một số rối loạn đông máu.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0382', 'S3.2', 1, 'single_choice', 'Chế phẩm máu cần được bảo quản đúng nhiệt độ vì:', '["Tiết kiệm điện", "Bảo đảm chất lượng và an toàn của chế phẩm", "Thẩm mỹ", "Dễ vận chuyển"]'::jsonb, 1, 'Mỗi chế phẩm (hồng cầu, tiểu cầu, huyết tương) có yêu cầu bảo quản riêng; sai nhiệt độ làm hỏng chế phẩm và mất an toàn.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0383', 'S3.2', 2, 'single_choice', 'Khối tiểu cầu thường được bảo quản ở điều kiện nào?', '["Đông lạnh -18 độ C", "Nhiệt độ phòng 20-24 độ C có lắc liên tục", "2-6 độ C tĩnh", "-80 độ C"]'::jsonb, 1, 'Tiểu cầu bảo quản ở 20-24 độ C với lắc liên tục để duy trì chức năng; không để lạnh như hồng cầu.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0384', 'S3.2', 2, 'single_choice', 'Nguyên tắc "chỉ định truyền máu hợp lý" nhấn mạnh:', '["Truyền càng nhiều càng tốt", "Truyền đúng chế phẩm, đúng chỉ định, liều tối thiểu có hiệu quả", "Luôn truyền máu toàn phần", "Truyền dự phòng cho mọi NB"]'::jsonb, 1, 'Truyền máu hợp lý: chọn đúng chế phẩm theo nhu cầu, đúng chỉ định và liều tối thiểu hiệu quả để giảm rủi ro.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0385', 'S3.3', 1, 'single_choice', 'Trong 15 phút đầu truyền máu, điều dưỡng cần:', '["Rời khỏi phòng", "Theo dõi sát NB để phát hiện sớm phản ứng truyền máu", "Tăng tốc độ tối đa", "Ngừng theo dõi dấu hiệu sinh tồn"]'::jsonb, 1, '15 phút đầu là thời điểm nguy cơ cao xảy ra phản ứng nặng; cần truyền chậm và theo dõi sát để phát hiện sớm.', '', ARRAY['KT02','KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0386', 'S3.3', 3, 'single_choice', 'Người bệnh đang truyền máu đột ngột sốt, rét run, đau lưng, nước tiểu sẫm màu. Xử trí ĐẦU TIÊN:', '["Tăng tốc độ truyền", "Ngừng truyền máu ngay, giữ đường truyền bằng NaCl 0,9% và báo bác sĩ", "Cho thuốc hạ sốt rồi truyền tiếp", "Rút kim"]'::jsonb, 1, 'Đây là dấu hiệu phản ứng tan máu cấp; phải ngừng truyền ngay, duy trì đường truyền bằng nước muối sinh lý và báo bác sĩ, giữ lại túi máu.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0387', 'S3.3', 2, 'single_choice', 'Phản ứng truyền máu tan máu cấp nặng thường do nguyên nhân nào?', '["Truyền quá chậm", "Truyền nhầm nhóm ABO không hòa hợp", "Máu để lạnh", "Dị ứng nhẹ"]'::jsonb, 1, 'Tan máu cấp nghiêm trọng nhất do bất đồng ABO (thường là sai sót định danh NB/đơn vị máu), có thể gây sốc và suy thận.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0388', 'S3.3', 1, 'single_choice', 'Dung dịch nào được phép dùng chung đường truyền với máu?', '["Glucose 5%", "NaCl 0,9%", "Ringer lactate", "Dung dịch có calci"]'::jsonb, 1, 'Chỉ NaCl 0,9% được dùng chung với máu; glucose gây ngưng tập hồng cầu, dịch có calci có thể gây đông trong dây truyền.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0389', 'S3.3', 2, 'single_choice', 'Phản ứng dị ứng nhẹ khi truyền máu (mày đay, ngứa) thường được xử trí:', '["Ngừng vĩnh viễn mọi truyền máu", "Tạm ngừng, dùng kháng histamin theo y lệnh, theo dõi rồi cân nhắc tiếp tục", "Tăng tốc độ", "Bỏ qua"]'::jsonb, 1, 'Dị ứng nhẹ: tạm ngừng, dùng kháng histamin theo y lệnh; nếu cải thiện có thể tiếp tục truyền chậm dưới theo dõi.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0390', 'S3.3', 3, 'single_choice', 'Quá tải tuần hoàn do truyền máu (TACO) biểu hiện điển hình:', '["Hạ huyết áp, sốt cao", "Khó thở, tăng huyết áp, ran ẩm phổi do quá tải dịch", "Ngứa đơn thuần", "Đau bụng"]'::jsonb, 1, 'TACO là quá tải thể tích: khó thở, phù phổi, tăng huyết áp; cần giảm/ngừng truyền, cho NB ngồi, thở oxy và xử trí theo y lệnh.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0391', 'S3.3', 2, 'single_choice', 'Kiểm tra "đúng người bệnh - đúng đơn vị máu" trước truyền cần thực hiện bởi:', '["Một người, làm nhanh", "Đối chiếu độc lập, thường hai người, khớp toàn bộ thông tin định danh", "Chỉ người nhà", "Không cần đối chiếu"]'::jsonb, 1, 'Đối chiếu định danh (thường hai người kiểm tra chéo) là hàng rào an toàn quan trọng để tránh truyền nhầm.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0392', 'S3.4', 2, 'single_choice', 'Tiêu chuẩn quan trọng để rút ống nội khí quản là người bệnh:', '["Còn mê sâu", "Tỉnh, tự thở hiệu quả, phản xạ bảo vệ đường thở phục hồi, oxy hóa đạt", "Còn giãn cơ", "Huyết áp thấp"]'::jsonb, 1, 'Rút NKQ an toàn khi NB tỉnh, tự thở tốt, có phản xạ ho/nuốt và oxy hóa đạt để tránh suy hô hấp và hít sặc sau rút.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0393', 'S3.4', 1, 'single_choice', 'Trước khi rút nội khí quản, cần hút sạch đàm ở:', '["Chỉ dạ dày", "Khoang miệng - hầu họng và trong ống để tránh hít dịch", "Không cần hút", "Chỉ mũi"]'::jsonb, 1, 'Hút sạch dịch trong ống và vùng hầu họng trước khi xả cuff và rút để tránh dịch tràn vào đường thở.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0394', 'S3.4', 3, 'single_choice', 'Biến chứng nguy hiểm ngay sau rút nội khí quản cần theo dõi sát là:', '["Táo bón", "Co thắt thanh quản/phù nề thanh môn gây tắc nghẽn đường thở", "Tăng đường huyết", "Loét tì đè"]'::jsonb, 1, 'Sau rút NKQ có thể co thắt thanh quản hoặc phù nề thanh môn gây tắc đường thở; cần chuẩn bị oxy, dụng cụ và theo dõi sát.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0395', 'S3.4', 2, 'single_choice', 'Sau rút nội khí quản, người bệnh nên được:', '["Cho ăn ngay lập tức", "Cung cấp oxy, theo dõi SpO2, kiểu thở và dấu hiệu suy hô hấp", "Rời phòng ngay", "Nằm đầu thấp"]'::jsonb, 1, 'Sau rút cần cho thở oxy, theo dõi SpO2, nhịp và kiểu thở, tiếng thở để phát hiện sớm suy hô hấp.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0396', 'S3.4', 1, 'single_choice', 'Việc xả hơi bóng chèn (cuff) trước khi rút ống nhằm:', '["Giảm đau", "Tránh tổn thương niêm mạc khí quản và cho phép rút ống", "Tăng thông khí", "Giữ ống lâu hơn"]'::jsonb, 1, 'Phải xả cuff hoàn toàn trước khi rút để tránh làm tổn thương niêm mạc khí quản - thanh môn.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0397', 'S3.4', 2, 'single_choice', '"Rút ống thất bại" (cần đặt lại nội khí quản) thường do:', '["NB quá tỉnh", "Suy hô hấp, tắc nghẽn đường thở hoặc mất khả năng bảo vệ đường thở", "Huyết áp cao", "Đau nhẹ"]'::jsonb, 1, 'Thất bại rút ống do đánh giá chưa đủ tiêu chuẩn: suy hô hấp, tắc nghẽn, yếu cơ hô hấp hoặc mất phản xạ bảo vệ.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0398', 'S3.5', 1, 'single_choice', 'Điều dưỡng dụng cụ (scrub nurse) có vai trò chính:', '["Ghi hồ sơ ngoài", "Duy trì vùng vô khuẩn, chuẩn bị và đưa dụng cụ cho phẫu thuật viên", "Gây mê", "Vận chuyển NB"]'::jsonb, 1, 'ĐD dụng cụ đứng trong vùng vô khuẩn, quản lý bàn dụng cụ, đưa dụng cụ và đếm gạc/kim cùng ĐD vòng ngoài.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0399', 'S3.5', 1, 'single_choice', 'Điều dưỡng vòng ngoài (circulating nurse) KHÔNG làm nhiệm vụ nào?', '["Đối chiếu NB, chuẩn bị phòng", "Trực tiếp cầm dụng cụ trong vùng vô khuẩn liên tục", "Ghi chép, tiếp dụng cụ vô khuẩn từ ngoài", "Phối hợp đếm gạc"]'::jsonb, 1, 'ĐD vòng ngoài hoạt động ngoài vùng vô khuẩn (không mặc áo vô khuẩn cầm dụng cụ liên tục); hỗ trợ hậu cần, ghi chép, đối chiếu.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0400', 'S3.5', 2, 'single_choice', 'Khi mở gói dụng cụ vô khuẩn, mép bao ngoài cùng được coi là:', '["Vô khuẩn", "Không vô khuẩn (vùng bẩn)", "Vùng đệm", "Không quan trọng"]'::jsonb, 1, 'Mép ngoài (khoảng 2,5 cm) của bao/khăn vô khuẩn được coi là không vô khuẩn; chỉ vùng trong mới vô khuẩn.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0401', 'S3.5', 2, 'single_choice', 'Nguyên tắc "vật vô khuẩn chạm vật không vô khuẩn thì trở thành:', '["Vẫn vô khuẩn", "Không vô khuẩn (nhiễm)", "Bán vô khuẩn", "Không đổi"]'::jsonb, 1, 'Bất kỳ tiếp xúc với vật không vô khuẩn đều làm mất vô khuẩn — nguyên tắc cơ bản của kỹ thuật vô khuẩn.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0402', 'S3.5', 3, 'single_choice', 'Trong mổ, khi nghi ngờ một dụng cụ đã mất vô khuẩn, xử trí đúng là:', '["Tiếp tục dùng nếu trông sạch", "Loại bỏ/thay dụng cụ, coi như đã nhiễm", "Lau cồn rồi dùng lại ngay", "Hỏi người bệnh"]'::jsonb, 1, 'Nguyên tắc an toàn: khi nghi ngờ vô khuẩn thì coi như đã nhiễm và phải thay/loại bỏ, không dùng cho vùng phẫu thuật.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0403', 'S3.5', 1, 'single_choice', 'Vùng vô khuẩn trên áo choàng phẫu thuật thường được tính từ:', '["Toàn bộ áo", "Ngang ngực đến ngang thắt lưng, mặt trước và tay áo", "Chỉ tay áo", "Lưng áo"]'::jsonb, 1, 'Vùng vô khuẩn của áo choàng là mặt trước từ ngang ngực đến thắt lưng và tay áo; lưng và dưới thắt lưng coi là không vô khuẩn.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0404', 'S3.5', 2, 'single_choice', 'Khi hai người mặc áo vô khuẩn cần đổi chỗ cho nhau, nguyên tắc là:', '["Quay lưng vào nhau, giữ khoảng cách vùng vô khuẩn", "Quay mặt vào nhau sát nhau", "Chạm lưng vào nhau", "Đi qua khu bẩn"]'::jsonb, 0, 'Người mặc áo vô khuẩn di chuyển bằng cách quay lưng - đối - lưng hoặc mặt - đối - mặt giữ khoảng cách, tránh chạm vùng không vô khuẩn.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0405', 'S3.6', 1, 'single_choice', 'Sắp xếp bàn dụng cụ mổ cần tuân theo nguyên tắc:', '["Tùy hứng", "Có tổ chức, theo trình tự sử dụng và kiểm đếm được", "Càng nhiều càng tốt", "Không phân loại"]'::jsonb, 1, 'Bàn dụng cụ được sắp có tổ chức theo trình tự thì mổ, dễ lấy và kiểm đếm giúp thao tác nhanh và an toàn.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0406', 'S3.6', 2, 'single_choice', 'Kiểm tra chỉ thị (indicator) hấp tiệt khuẩn trên gói dụng cụ trước khi dùng nhằm:', '["Xác định hạn dùng đơn thuần", "Xác nhận gói đã trải qua quá trình tiệt khuẩn đạt", "Trang trí", "Đếm số lượng"]'::jsonb, 1, 'Chỉ thị hóa học/sinh học xác nhận gói đã qua chu trình tiệt khuẩn đạt yêu cầu trước khi mở dùng.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0407', 'S3.6', 2, 'single_choice', 'Một gói dụng cụ vô khuẩn bị ẩm/ướt thì được xem là:', '["Vẫn vô khuẩn", "Mất vô khuẩn, không được sử dụng", "Chỉ dùng ngoài da", "Vô khuẩn nếu khô lại"]'::jsonb, 1, 'Ẩm ướt tạo đường cho vi khuẩn thấm qua bao gói (strike-through), làm mất vô khuẩn — phải loại bỏ.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0408', 'S3.6', 1, 'single_choice', 'Trước ca mổ, việc kiểm tra đủ số lượng và tình trạng dụng cụ nhằm:', '["Cho đẹp", "Bảo đảm sẵn sàng, tránh thiếu/hỏng dụng cụ giữa cuộc mổ", "Giảm chi phí", "Đếm cho vui"]'::jsonb, 1, 'Chuẩn bị và kiểm tra dụng cụ đầy đủ, còn tốt trước mổ giúp cuộc mổ diễn ra an toàn, liên tục.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0409', 'S3.6', 3, 'single_choice', 'Đếm gạc, kim, dụng cụ được thực hiện tối thiểu vào các thời điểm:', '["Chỉ đầu mổ", "Trước mổ, trước khi đóng khoang và khi kết thúc (và khi đổi kíp)", "Chỉ cuối mổ", "Không cần đếm"]'::jsonb, 1, 'Quy trình đếm chuẩn thực hiện trước mổ, trước khi đóng khoang cơ thể, khi kết thúc và khi thay đổi kíp để tránh sót dị vật.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0410', 'S3.6', 2, 'single_choice', 'Dụng cụ sau mổ phải được xử lý theo trình tự đúng là:', '["Cất ngay vào tủ", "Làm sạch (khử nhiễm) sang khử khuẩn/tiệt khuẩn theo quy trình", "Chỉ lau khô", "Bỏ đi"]'::jsonb, 1, 'Dụng cụ tái sử dụng phải trải qua khử nhiễm/làm sạch sang đóng gói sang tiệt khuẩn theo quy trình trước khi dùng lại.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0411', 'S3.7', 1, 'single_choice', 'Đặt thông tiểu (sonde tiểu) phải tuân thủ nguyên tắc:', '["Sạch thông thường", "Vô khuẩn (aseptic technique)", "Không cần găng", "Tùy điều kiện"]'::jsonb, 1, 'Đặt thông tiểu là thủ thuật vô khuẩn để phòng nhiễm khuẩn tiết niệu liên quan đặt thông (CAUTI).', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0412', 'S3.7', 2, 'single_choice', 'Biện pháp quan trọng nhất để phòng nhiễm khuẩn tiết niệu do thông tiểu là:', '["Thay thông mỗi ngày", "Chỉ đặt khi có chỉ định và rút sớm nhất có thể", "Kẹp thông liên tục", "Bơm rửa thường quy"]'::jsonb, 1, 'Giảm CAUTI hiệu quả nhất bằng cách hạn chế chỉ định, đặt đúng kỹ thuật vô khuẩn và rút thông càng sớm càng tốt.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0413', 'S3.7', 1, 'single_choice', 'Túi chứa nước tiểu phải luôn được đặt:', '["Cao hơn bàng quang", "Thấp hơn bàng quang và không chạm sàn", "Ngang bàng quang", "Trên bụng NB"]'::jsonb, 1, 'Túi dẫn lưu đặt thấp hơn bàng quang để dẫn lưu theo trọng lực và tránh trào ngược, đồng thời không chạm sàn nhà.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0414', 'S3.7', 2, 'single_choice', 'Bóng chèn (balloon) của thông tiểu Foley chỉ được bơm khi:', '["Vừa đưa vào niệu đạo", "Chắc chắn đầu thông đã vào bàng quang (thấy nước tiểu ra)", "Trước khi đặt", "Sau khi rút một phần"]'::jsonb, 1, 'Chỉ bơm bóng khi đã vào bàng quang (có nước tiểu chảy ra); bơm sớm trong niệu đạo gây tổn thương nặng.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0415', 'S3.7', 3, 'single_choice', 'Theo dõi dẫn lưu nước tiểu ở NB sau mổ giúp đánh giá:', '["Chức năng gan", "Tưới máu thận và cân bằng dịch (thiểu niệu gợi ý giảm thể tích)", "Đông máu", "Hô hấp"]'::jsonb, 1, 'Lượng nước tiểu phản ánh tưới máu thận và thể tích tuần hoàn; thiểu niệu cảnh báo giảm thể tích hoặc tổn thương thận.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0416', 'S3.7', 1, 'single_choice', 'Vệ sinh vùng sinh dục - lỗ niệu đạo hằng ngày ở NB mang thông tiểu nhằm:', '["Thẩm mỹ", "Giảm nguy cơ nhiễm khuẩn ngược dòng", "Tăng lưu lượng", "Giữ thông lâu hơn"]'::jsonb, 1, 'Vệ sinh vùng quanh lỗ niệu đạo giúp giảm vi khuẩn xâm nhập dọc thông, hạn chế nhiễm khuẩn tiết niệu.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0417', 'S3.8', 1, 'single_choice', 'Trước khởi mê, việc chuẩn bị phương tiện hồi sức và đường thở khó cần:', '["Không cần thiết", "Sẵn sàng bóng - mặt nạ, oxy, dụng cụ đặt NKQ và thuốc cấp cứu", "Chỉ chuẩn bị oxy", "Chuẩn bị sau khi khởi mê"]'::jsonb, 1, 'Phải kiểm tra và sẵn sàng bóng-mặt nạ, nguồn oxy, đèn - ống NKQ, máy hút và thuốc cấp cứu trước khi khởi mê.', '', ARRAY['KT07','KT08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0418', 'S3.8', 2, 'single_choice', '"Tiền oxy hóa" (preoxygenation) trước đặt nội khí quản nhằm:', '["Giảm đau", "Kéo dài thời gian an toàn trước khi thiếu oxy trong lúc đặt ống", "Hạ huyết áp", "Gây ngủ"]'::jsonb, 1, 'Cho thở oxy 100% trước khởi mê làm tăng dự trữ oxy, kéo dài thời gian ngưng thở an toàn khi đặt NKQ.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0419', 'S3.8', 2, 'single_choice', 'Nghiệm pháp ấn sụn nhẫn (Sellick) trong khởi mê nhanh nhằm:', '["Mở thanh môn", "Giảm nguy cơ trào ngược - hít sặc khi khởi mê", "Cố định ống", "Giảm đau"]'::jsonb, 1, 'Ấn sụn nhẫn ép thực quản nhằm hạn chế trào ngược dịch dạ dày trong khởi mê nhanh (RSI) ở NB dạ dày đầy.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0420', 'S3.8', 2, 'single_choice', 'Dấu hiệu tin cậy xác nhận ống nội khí quản nằm đúng trong khí quản là:', '["Nghe bụng ùng ục", "Đường cong CO2 cuối thì thở ra (capnography) dương tính liên tục", "SpO2 tăng chậm", "NB nằm yên"]'::jsonb, 1, 'Capnography (EtCO2) có dạng sóng liên tục là tiêu chuẩn tin cậy xác nhận ống trong khí quản; nghe phổi hai bên bổ sung.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0421', 'S3.8', 3, 'single_choice', 'Sau đặt ống, nghe phổi thấy phế âm chỉ rõ bên phải, bên trái giảm — nghĩ nhiều đến:', '["Ống vào thực quản", "Ống vào sâu một bên (phế quản gốc phải)", "Tràn khí màng phổi trái chắc chắn", "Bình thường"]'::jsonb, 1, 'Phế âm không đều (mạnh bên phải) gợi ý ống vào sâu phế quản gốc phải; cần rút bớt ống và nghe lại hai bên.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0422', 'S3.8', 1, 'single_choice', 'Trong lúc gây mê, điều dưỡng phụ mê cần theo dõi liên tục các thông số:', '["Chỉ mạch", "SpO2, EtCO2, mạch, huyết áp, điện tim và độ mê", "Chỉ nhiệt độ", "Chỉ nước tiểu"]'::jsonb, 1, 'Theo dõi tối thiểu trong gây mê gồm SpO2, EtCO2, mạch, huyết áp, ECG và độ mê để phát hiện sớm biến cố.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0423', 'S3.8', 3, 'single_choice', 'Tăng thân nhiệt ác tính (malignant hyperthermia) là biến chứng gây mê liên quan chủ yếu đến:', '["Opioid", "Thuốc mê bốc hơi và succinylcholine ở người có cơ địa nhạy cảm", "Dịch truyền", "Kháng sinh"]'::jsonb, 1, 'Tăng thân nhiệt ác tính là phản ứng chuyển hóa nặng do thuốc mê hô hấp và succinylcholine ở người có cơ địa di truyền; xử trí bằng dantrolene và ngừng tác nhân.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0424', 'S3.8', 2, 'single_choice', 'Chuẩn bị máy gây mê trước ca (kiểm tra rò, van, vôi soda, nguồn oxy) là trách nhiệm nhằm:', '["Thủ tục hình thức", "Bảo đảm an toàn, phát hiện lỗi thiết bị trước khi gây mê", "Tiết kiệm khí", "Rút ngắn mổ"]'::jsonb, 1, 'Kiểm tra máy gây mê trước mỗi ca (machine check) phát hiện rò rỉ, hỏng van, hết vôi soda... trước khi gây mê để bảo đảm an toàn.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0425', 'S4.1', 1, 'single_choice', '"Phòng ngừa chuẩn" (Standard Precautions) được áp dụng cho:', '["Chỉ NB nhiễm HIV", "Tất cả người bệnh, mọi lúc, không phụ thuộc chẩn đoán", "Chỉ khu cách ly", "Chỉ khi thấy máu"]'::jsonb, 1, 'Phòng ngừa chuẩn áp dụng cho MỌI người bệnh vì coi mọi máu/dịch cơ thể đều có nguy cơ lây nhiễm.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0426', 'S4.1', 2, 'single_choice', 'Thời điểm vệ sinh tay theo WHO gồm "5 thời điểm", trong đó có:', '["Chỉ sau khi ăn", "Trước khi tiếp xúc NB và sau khi tiếp xúc dịch cơ thể", "Chỉ đầu ca", "Chỉ khi tay bẩn nhìn thấy"]'::jsonb, 1, '5 thời điểm vệ sinh tay: trước tiếp xúc NB, trước làm thủ thuật vô khuẩn, sau nguy cơ tiếp xúc dịch, sau tiếp xúc NB, sau tiếp xúc môi trường quanh NB.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0427', 'S4.1', 1, 'single_choice', 'Khi tay dính máu/dịch cơ thể nhìn thấy được, nên vệ sinh tay bằng:', '["Dung dịch chứa cồn", "Rửa tay với xà phòng và nước", "Chỉ lau khăn", "Không cần"]'::jsonb, 1, 'Khi tay bẩn nhìn thấy hoặc dính dịch, phải rửa bằng xà phòng và nước; dung dịch cồn không loại bỏ được vết bẩn hữu cơ.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0428', 'S4.1', 2, 'single_choice', 'Phương tiện phòng hộ cá nhân (PPE) được chọn dựa trên:', '["Sở thích", "Đánh giá nguy cơ phơi nhiễm của thao tác", "Luôn mặc đầy đủ mọi thứ", "Chỉ khẩu trang"]'::jsonb, 1, 'Lựa chọn PPE (găng, khẩu trang, kính, áo choàng) tùy theo nguy cơ tiếp xúc máu/dịch của từng thao tác.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0429', 'S4.1', 3, 'single_choice', 'Thứ tự tháo bỏ PPE an toàn (khi có găng, áo choàng, kính, khẩu trang) thường là:', '["Khẩu trang trước tiên", "Găng và áo choàng trước, vệ sinh tay, rồi kính và khẩu trang sau cùng", "Kính trước tiên", "Không theo thứ tự"]'::jsonb, 1, 'Nguyên tắc tháo PPE: bỏ các vật bẩn nhất (găng, áo choàng) trước, vệ sinh tay, tháo kính/khẩu trang sau cùng và vệ sinh tay lại, tránh nhiễm bẩn.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0430', 'S4.1', 1, 'single_choice', 'Xử lý vật sắc nhọn (kim, dao) sau dùng đúng cách là:', '["Đậy nắp kim bằng hai tay", "Bỏ ngay vào hộp kháng thủng, không đậy lại nắp kim", "Bẻ cong kim", "Bỏ chung rác thường"]'::jsonb, 1, 'Không đậy lại nắp kim (recapping) bằng hai tay; bỏ ngay vào hộp kháng thủng để phòng tổn thương do vật sắc nhọn.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0431', 'S4.1', 2, 'single_choice', 'Phòng ngừa dựa trên đường lây "giọt bắn" (droplet) cần thêm:', '["Phòng áp lực âm", "Mang khẩu trang y tế khi ở gần NB, giữ khoảng cách", "Chỉ găng tay", "Không cần gì thêm"]'::jsonb, 1, 'Phòng ngừa giọt bắn (cúm, ho gà...) cần khẩu trang y tế khi tiếp xúc gần; khác với đường không khí cần khẩu trang N95 và phòng áp lực âm.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0432', 'S4.1', 2, 'single_choice', 'Bệnh lây qua đường không khí (ví dụ lao phổi) cần biện pháp phòng hộ:', '["Khẩu trang y tế thường", "Khẩu trang N95 và phòng cách ly áp lực âm", "Chỉ rửa tay", "Chỉ áo choàng"]'::jsonb, 1, 'Đường không khí (lao, sởi, thủy đậu) cần khẩu trang hô hấp N95 và buồng cách ly áp lực âm để ngăn khí dung lây lan.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0433', 'S4.2', 2, 'single_choice', 'Nhiễm khuẩn vết mổ (SSI) được phân loại theo độ sâu, KHÔNG bao gồm loại nào?', '["Nông (da, mô dưới da)", "Sâu (cân, cơ)", "Cơ quan/khoang", "Nhiễm khuẩn tiết niệu"]'::jsonb, 3, 'SSI phân loại: nông, sâu và cơ quan/khoang; nhiễm khuẩn tiết niệu là loại nhiễm khuẩn bệnh viện khác, không thuộc SSI.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0434', 'S4.2', 2, 'single_choice', 'Thời điểm dùng kháng sinh dự phòng phẫu thuật tối ưu là:', '["Sau khi đóng da", "Trong vòng 60 phút trước khi rạch da", "24 giờ trước mổ", "Chỉ khi có sốt"]'::jsonb, 1, 'Kháng sinh dự phòng cho hiệu quả tốt nhất khi đạt nồng độ mô đủ lúc rạch da, thường tiêm trong 60 phút trước rạch da.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0435', 'S4.2', 1, 'single_choice', 'Biện pháp đơn giản nhưng hiệu quả nhất phòng ngừa nhiễm khuẩn bệnh viện là:', '["Dùng kháng sinh phổ rộng", "Vệ sinh tay đúng cách", "Cách ly mọi NB", "Mặc nhiều PPE"]'::jsonb, 1, 'Vệ sinh tay là biện pháp đơn giản, rẻ và hiệu quả nhất để cắt đứt lây truyền nhiễm khuẩn trong bệnh viện.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0436', 'S4.2', 2, 'single_choice', 'Phân loại chất thải y tế lây nhiễm thường được đựng trong túi/thùng màu:', '["Xanh", "Vàng", "Đen", "Trắng"]'::jsonb, 1, 'Chất thải lây nhiễm được thu gom trong túi/thùng màu vàng theo quy định phân loại chất thải y tế.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0437', 'S4.2', 3, 'single_choice', 'Giám sát nhiễm khuẩn bệnh viện chủ động nhằm mục đích:', '["Xử phạt nhân viên", "Phát hiện, phân tích xu hướng và can thiệp giảm nhiễm khuẩn", "Tăng dùng kháng sinh", "Thống kê hình thức"]'::jsonb, 1, 'Giám sát NKBV giúp phát hiện sớm ổ dịch, đo lường tỷ lệ, phân tích nguyên nhân và triển khai can thiệp cải tiến.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0438', 'S4.2', 1, 'single_choice', 'Khử khuẩn dụng cụ tiếp xúc niêm mạc nguyên vẹn (ví dụ ống soi) tối thiểu cần đạt mức:', '["Làm sạch đơn thuần", "Khử khuẩn mức độ cao", "Chỉ lau cồn", "Không cần xử lý"]'::jsonb, 1, 'Theo phân loại Spaulding, dụng cụ bán thiết yếu (tiếp xúc niêm mạc) cần khử khuẩn mức độ cao tối thiểu.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0439', 'S4.2', 2, 'single_choice', 'Dụng cụ "thiết yếu" (critical) đưa vào mô vô khuẩn/mạch máu bắt buộc phải:', '["Khử khuẩn mức thấp", "Tiệt khuẩn", "Chỉ rửa sạch", "Lau cồn"]'::jsonb, 1, 'Dụng cụ thiết yếu (dao mổ, dụng cụ phẫu thuật) tiếp xúc mô vô khuẩn phải được tiệt khuẩn theo phân loại Spaulding.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0440', 'S4.3', 2, 'single_choice', 'Mục tiêu của Bảng kiểm an toàn phẫu thuật là:', '["Đánh giá tay nghề", "Giảm sai sót và biến chứng có thể phòng ngừa trong phẫu thuật", "Tính chi phí", "Xếp lịch mổ"]'::jsonb, 1, 'Checklist an toàn phẫu thuật (WHO/BYT) nhằm chuẩn hóa các bước kiểm tra, giảm biến cố phòng ngừa được và tăng giao tiếp kíp mổ.', '', ARRAY['VB05','VB10'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0441', 'S4.3', 1, 'single_choice', 'Bước "Time out" ngay trước khi rạch da nhằm xác nhận:', '["Chi phí mổ", "Đúng người bệnh, đúng vị trí, đúng thủ thuật và các nguy cơ", "Số lượng khách thăm", "Ca kế tiếp"]'::jsonb, 1, 'Time out là khoảng dừng để cả kíp xác nhận đúng NB - vị trí - thủ thuật, kháng sinh dự phòng và các nguy cơ dự kiến.', '', ARRAY['VB05','VB10'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0442', 'S4.3', 2, 'single_choice', 'Đánh dấu vị trí phẫu thuật (site marking) nên được thực hiện:', '["Sau khi gây mê", "Khi NB còn tỉnh, có sự tham gia xác nhận của NB trước mổ", "Không cần thiết", "Bởi người nhà"]'::jsonb, 1, 'Đánh dấu vị trí mổ khi NB còn tỉnh và tham gia xác nhận giúp phòng ngừa mổ nhầm vị trí (wrong-site surgery).', '', ARRAY['VB05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0443', 'S4.3', 3, 'single_choice', 'Sự cố "không bao giờ được phép xảy ra" (never events) trong phẫu thuật bao gồm:', '["Đau sau mổ", "Mổ nhầm vị trí/nhầm người, sót dụng cụ trong cơ thể", "Buồn nôn", "Sốt nhẹ"]'::jsonb, 1, 'Never events là sự cố nghiêm trọng lẽ ra phòng ngừa được: mổ nhầm vị trí/người/thủ thuật, sót gạc-dụng cụ; cần rà soát hệ thống khi xảy ra.', '', ARRAY['VB05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0444', 'S4.3', 1, 'single_choice', 'Đếm gạc và dụng cụ trước khi đóng vết mổ là một phần của:', '["Thủ tục tài chính", "Bảo đảm an toàn phẫu thuật, phòng sót dị vật", "Nghiên cứu", "Đào tạo"]'::jsonb, 1, 'Đếm gạc/dụng cụ trước khi đóng khoang là biện pháp an toàn bắt buộc để phòng sót dị vật trong cơ thể NB.', '', ARRAY['VB05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0445', 'S4.3', 2, 'single_choice', 'Văn hóa an toàn người bệnh khuyến khích báo cáo sự cố theo hướng:', '["Quy trách nhiệm cá nhân để phạt", "Không quy kết (no-blame), tập trung cải tiến hệ thống", "Giấu sự cố", "Chỉ báo cáo khi tử vong"]'::jsonb, 1, 'Văn hóa an toàn hiện đại khuyến khích báo cáo tự nguyện, không quy kết, để học hỏi và cải tiến hệ thống thay vì trừng phạt.', '', ARRAY['VB05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0446', 'S4.4', 1, 'single_choice', 'Nguyên tắc quản lý kho vật tư "FEFO" nghĩa là:', '["Nhập sau xuất trước", "Hết hạn trước thì xuất trước (First Expired First Out)", "Xuất ngẫu nhiên", "Giữ hàng cũ lại"]'::jsonb, 1, 'FEFO ưu tiên xuất vật tư có hạn dùng đến trước để giảm hao hụt do hết hạn, quan trọng với vật tư/thuốc y tế.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0447', 'S4.4', 2, 'single_choice', 'Kiểm tra hạn dùng và tính toàn vẹn bao gói vật tư vô khuẩn trước khi dùng nhằm:', '["Thẩm mỹ", "Bảo đảm vật tư còn vô khuẩn và an toàn cho NB", "Đếm tồn kho", "Tính giá"]'::jsonb, 1, 'Trước khi dùng phải kiểm tra hạn dùng và bao gói còn nguyên vẹn, khô ráo — bao rách/ẩm/hết hạn là không an toàn.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0448', 'S4.4', 1, 'single_choice', 'Tem/nhãn vật tư y tế cần thể hiện thông tin tối thiểu:', '["Chỉ tên hàng", "Tên, quy cách, số lô, hạn dùng và điều kiện bảo quản", "Chỉ giá", "Chỉ nhà sản xuất"]'::jsonb, 1, 'Nhãn vật tư cần đủ tên, quy cách, số lô, hạn dùng và điều kiện bảo quản để truy xuất và sử dụng an toàn.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0449', 'S4.4', 2, 'single_choice', 'Quản lý vật tư tiêu hao trong phòng mổ cần bảo đảm:', '["Tồn kho càng nhiều càng tốt", "Đủ dùng, đúng chủng loại, kiểm soát hạn dùng và truy xuất được", "Không cần kiểm kê", "Dùng chung mọi loại"]'::jsonb, 1, 'Quản lý tốt vật tư mổ: đủ số lượng, đúng chủng loại, kiểm soát hạn dùng và truy xuất số lô khi cần.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0450', 'S4.4', 3, 'single_choice', 'Khi phát hiện vật tư y tế bị lỗi/nghi ngờ chất lượng, xử trí đúng là:', '["Vẫn dùng cho đỡ lãng phí", "Ngừng sử dụng, cách ly lô hàng, báo cáo và truy xuất", "Vứt lặng lẽ", "Chỉ dùng cho ca nhẹ"]'::jsonb, 1, 'Vật tư lỗi/nghi ngờ chất lượng phải ngừng dùng ngay, cách ly, báo cáo và truy xuất số lô để xử lý toàn bộ lô liên quan.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0451', 'S4.4', 1, 'single_choice', 'Bảo quản vật tư y tế cần điều kiện:', '["Bất kỳ nơi nào", "Kho sạch, khô, đúng nhiệt độ/độ ẩm và tránh ánh sáng theo yêu cầu", "Ngoài trời", "Cạnh chất thải"]'::jsonb, 1, 'Vật tư cần bảo quản nơi sạch, khô, đúng điều kiện nhiệt độ/độ ẩm nhà sản xuất quy định để giữ chất lượng.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0452', 'S4.4', 2, 'single_choice', 'Kiểm kê định kỳ vật tư y tế nhằm mục đích:', '["Hình thức", "Đối chiếu sổ sách - thực tế, phát hiện thiếu hụt/hết hạn và điều chỉnh", "Tăng chi phí", "Giảm nhân sự"]'::jsonb, 1, 'Kiểm kê định kỳ giúp khớp tồn kho thực tế với sổ sách, phát hiện hao hụt, hàng hết hạn và lập kế hoạch bổ sung.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0453', 'S5.1', 1, 'single_choice', 'Trình tự hồi sinh tim phổi cơ bản (BLS) cho người lớn hiện nay là:', '["A-B-C", "C-A-B (ép tim trước)", "Chỉ thổi ngạt", "B-C-A"]'::jsonb, 1, 'Hướng dẫn hiện hành ưu tiên C-A-B: bắt đầu ép tim ngay, sau đó đường thở và thổi ngạt để giảm gián đoạn tuần hoàn.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0454', 'S5.1', 2, 'single_choice', 'Tần số ép tim ngoài lồng ngực cho người lớn là:', '["60-80 lần/phút", "100-120 lần/phút", "140-160 lần/phút", "Dưới 60 lần/phút"]'::jsonb, 1, 'Ép tim chất lượng cao: tần số 100-120 lần/phút, độ sâu 5-6 cm và để ngực nảy lại hoàn toàn.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0455', 'S5.1', 2, 'single_choice', 'Độ sâu ép tim cho người lớn nên đạt:', '["1-2 cm", "5-6 cm", "8-10 cm", "Càng sâu càng tốt"]'::jsonb, 1, 'Ép sâu 5-6 cm ở người lớn tạo cung lượng tim hiệu quả; nông quá không hiệu quả, sâu quá gây chấn thương.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0456', 'S5.1', 1, 'single_choice', 'Tỷ lệ ép tim/thổi ngạt trong CPR người lớn (một hoặc hai người, chưa đặt NKQ) là:', '["15:2", "30:2", "5:1", "50:2"]'::jsonb, 1, 'Tỷ lệ chuẩn cho người lớn là 30 lần ép tim : 2 lần thổi ngạt khi chưa có đường thở nâng cao.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0457', 'S5.1', 3, 'single_choice', 'Khi có máy khử rung tự động (AED) và nhịp là rung thất, cần:', '["Không sốc, chỉ ép tim", "Sốc điện càng sớm càng tốt rồi tiếp tục CPR", "Chờ bác sĩ đến", "Cho thuốc trước"]'::jsonb, 1, 'Rung thất/nhịp nhanh thất vô mạch là nhịp cần sốc; khử rung sớm cùng CPR chất lượng cao làm tăng khả năng sống.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0458', 'S5.1', 2, 'single_choice', 'Xử trí dị vật đường thở gây tắc nghẽn hoàn toàn ở người lớn còn tỉnh:', '["Vỗ lưng nhẹ", "Nghiệm pháp Heimlich (ép bụng) đến khi tống dị vật hoặc NB bất tỉnh", "Cho uống nước", "Móc họng mù"]'::jsonb, 1, 'Tắc nghẽn hoàn toàn ở người còn tỉnh: thực hiện ép bụng (Heimlich); nếu bất tỉnh thì bắt đầu CPR.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0459', 'S5.1', 1, 'single_choice', 'Khi tiếp cận nạn nhân bất tỉnh, bước đầu tiên là:', '["Ép tim ngay", "Bảo đảm hiện trường an toàn và kiểm tra đáp ứng", "Gọi người nhà", "Cho ăn"]'::jsonb, 1, 'Nguyên tắc DRS: bảo đảm an toàn hiện trường, kiểm tra đáp ứng, rồi gọi hỗ trợ trước khi đánh giá tuần hoàn/hô hấp.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0460', 'S5.1', 2, 'single_choice', 'Mục tiêu giảm tối đa gián đoạn ép tim trong CPR vì:', '["Đỡ mệt", "Gián đoạn làm tụt tưới máu vành/não, giảm cơ hội sống", "Tiết kiệm thời gian", "Không có lý do"]'::jsonb, 1, 'Mỗi lần dừng ép tim làm tụt áp lực tưới máu vành và não; hạn chế gián đoạn (<10 giây) cải thiện kết cục.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0461', 'S5.2', 1, 'single_choice', 'Việc đầu tiên khi nghi ngờ phản ứng truyền máu là:', '["Cho hạ sốt", "Ngừng truyền máu ngay lập tức", "Tăng tốc độ", "Đổi túi máu khác"]'::jsonb, 1, 'Bất kỳ nghi ngờ phản ứng truyền máu đều phải ngừng truyền ngay, giữ đường truyền bằng NaCl 0,9% và đánh giá NB.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0462', 'S5.2', 3, 'single_choice', 'Trong phản ứng phản vệ do truyền máu, thuốc điều trị đầu tay là:', '["Kháng histamin đơn thuần", "Adrenaline (epinephrine) tiêm bắp", "Kháng sinh", "Lợi tiểu"]'::jsonb, 1, 'Phản vệ cần adrenaline tiêm bắp ngay lập tức là điều trị đầu tay, kèm bảo đảm đường thở, oxy và dịch.', '', ARRAY['KT02','CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0463', 'S5.2', 2, 'single_choice', 'Sau khi ngừng truyền do phản ứng nặng, cần bảo quản và gửi lại:', '["Bỏ túi máu đi", "Túi máu còn lại và dây truyền để xét nghiệm điều tra", "Chỉ ghi hồ sơ", "Kim tiêm"]'::jsonb, 1, 'Giữ lại túi máu, dây truyền và lấy mẫu NB gửi ngân hàng máu để điều tra nguyên nhân (đối chiếu nhóm, cấy...).', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0464', 'S5.2', 2, 'single_choice', 'Theo dõi nước tiểu trong phản ứng tan máu cấp nhằm phát hiện:', '["Tăng đường huyết", "Tiểu hemoglobin và suy thận cấp", "Táo bón", "Tăng cân"]'::jsonb, 1, 'Tan máu cấp giải phóng hemoglobin gây nước tiểu sẫm và có thể suy thận cấp; cần theo dõi nước tiểu và duy trì tưới máu thận.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0465', 'S5.2', 1, 'single_choice', 'Sốt và rét run đơn thuần trong/ sau truyền máu có thể là phản ứng:', '["Tan máu chắc chắn", "Sốt không tan máu (febrile non-hemolytic) — vẫn phải ngừng và đánh giá", "Quá tải tuần hoàn", "Nhiễm trùng huyết luôn"]'::jsonb, 1, 'Phản ứng sốt không tan máu thường lành tính nhưng biểu hiện ban đầu giống tan máu; vẫn phải ngừng truyền và đánh giá loại trừ nguyên nhân nặng.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0466', 'S5.2', 3, 'single_choice', 'Nhiễm khuẩn huyết do truyền chế phẩm máu nhiễm khuẩn biểu hiện:', '["Không sốt", "Sốt cao, rét run, tụt huyết áp nhanh sau khi bắt đầu truyền", "Chỉ ngứa", "Tăng huyết áp đơn thuần"]'::jsonb, 1, 'Chế phẩm nhiễm khuẩn (thường tiểu cầu bảo quản ấm) gây sốc nhiễm khuẩn: sốt cao, rét run, tụt huyết áp; cần ngừng truyền, cấy máu và kháng sinh.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0467', 'S5.2', 2, 'single_choice', 'Biện pháp quan trọng nhất để phòng phản ứng tan máu cấp do ABO là:', '["Truyền chậm", "Định danh chính xác NB và đối chiếu đơn vị máu tại giường", "Hâm ấm máu", "Dùng thuốc dự phòng"]'::jsonb, 1, 'Tan máu ABO gần như luôn do lỗi định danh; đối chiếu đúng NB - đúng đơn vị máu tại giường là hàng rào phòng ngừa then chốt.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0468', 'S5.3', 3, 'single_choice', 'Người bệnh sau mổ đột ngột khó thở, nổi mày đay, tụt huyết áp sau dùng kháng sinh — nghĩ đến:', '["Đau vết mổ", "Phản vệ (anaphylaxis)", "Táo bón", "Hạ thân nhiệt"]'::jsonb, 1, 'Khởi phát nhanh mày đay + tụt huyết áp + khó thở sau thuốc là phản vệ; xử trí adrenaline tiêm bắp, oxy, dịch và gọi hỗ trợ ngay.', '', ARRAY['CS07','KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0469', 'S5.3', 2, 'single_choice', 'Tụt lưỡi gây tắc nghẽn đường thở ở NB lơ mơ sau mổ được xử trí đầu tiên bằng:', '["Cho ăn", "Thủ thuật ngửa đầu - nâng cằm (hoặc đẩy hàm) khai thông đường thở", "Chườm lạnh", "Đo đường huyết"]'::jsonb, 1, 'Tụt lưỡi là nguyên nhân tắc nghẽn thường gặp; ngửa đầu-nâng cằm hoặc đẩy hàm mở thông đường thở, cân nhắc canun hầu.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0470', 'S5.3', 3, 'single_choice', 'Người bệnh hồi tỉnh SpO2 tụt, thở chậm 6 lần/phút sau opioid — nguyên nhân và xử trí:', '["Đau, cho thêm opioid", "Ức chế hô hấp do opioid; hỗ trợ thông khí, oxy và cân nhắc naloxone", "Lo âu, trấn an", "Sốt, hạ sốt"]'::jsonb, 1, 'Thở chậm + tụt SpO2 sau opioid gợi ý ức chế hô hấp; hỗ trợ hô hấp, cung cấp oxy và dùng naloxone theo y lệnh để đối kháng.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0471', 'S5.3', 2, 'single_choice', 'Cơn tăng huyết áp kịch phát tại phòng hồi tỉnh cần loại trừ nguyên nhân thường gặp:', '["Hạ thân nhiệt", "Đau, kích thích, bí tiểu hoặc thiếu oxy/tăng CO2", "Đói", "Buồn ngủ"]'::jsonb, 1, 'Tăng huyết áp sau mổ thường do đau, kích thích, cầu bàng quang căng hoặc thiếu oxy; cần tìm và xử trí nguyên nhân trước khi dùng thuốc hạ áp.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0472', 'S5.3', 1, 'single_choice', 'Khi phát hiện người bệnh ngừng thở, ngừng tim tại phòng hồi tỉnh, cần:', '["Chờ bác sĩ", "Gọi hỗ trợ/khởi động báo động cấp cứu và bắt đầu CPR ngay", "Cho thở oxy rồi chờ", "Ghi hồ sơ trước"]'::jsonb, 1, 'Ngừng tuần hoàn cần kích hoạt hệ thống cấp cứu và bắt đầu ép tim ngay lập tức — thời gian là yếu tố sống còn.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0473', 'S5.3', 2, 'single_choice', 'Hạ thân nhiệt sau mổ (thường gặp) cần được xử trí vì có thể gây:', '["Không ảnh hưởng", "Run, tăng tiêu thụ oxy, rối loạn đông máu và loạn nhịp", "Giảm đau tốt", "Nhanh tỉnh hơn"]'::jsonb, 1, 'Hạ thân nhiệt làm run (tăng nhu cầu oxy), rối loạn đông máu, chậm chuyển hóa thuốc và tăng nguy cơ loạn nhịp; cần ủ ấm chủ động.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0474', 'S5.3', 3, 'single_choice', 'Thiếu oxy máu (hypoxemia) tại hồi tỉnh cần đánh giá theo hướng loại trừ nguyên nhân:', '["Chỉ do đau", "Tắc nghẽn đường thở, giảm thông khí, xẹp phổi, tồn dư thuốc", "Chỉ do lo âu", "Chỉ do đói"]'::jsonb, 1, 'Hypoxemia sau mổ có nhiều nguyên nhân: tắc nghẽn đường thở, giảm thông khí (tồn dư thuốc mê/giãn cơ), xẹp phổi, hít sặc; cần đánh giá hệ thống.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0475', 'S5.3', 2, 'single_choice', 'Bí tiểu cấp sau mổ gây khó chịu, kích thích, tăng huyết áp — xử trí phù hợp:', '["Bỏ qua", "Đánh giá cầu bàng quang, hỗ trợ tiểu hoặc đặt thông tiểu theo chỉ định", "Cho lợi tiểu liều cao ngay", "Hạn chế dịch tuyệt đối"]'::jsonb, 1, 'Bí tiểu sau mổ (do thuốc, đau, gây tê tủy sống) cần đánh giá cầu bàng quang và giải áp bằng hỗ trợ tiểu hoặc thông tiểu theo chỉ định.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0476', 'S6.1', 2, 'single_choice', 'Thông tư 31/2021/TT-BYT quy định về:', '["Giá dịch vụ y tế", "Hoạt động điều dưỡng trong bệnh viện", "Đấu thầu thuốc", "Bảo hiểm y tế"]'::jsonb, 1, 'TT31/2021 quy định nội dung hoạt động điều dưỡng trong bệnh viện: chăm sóc, tổ chức, nhân lực và bảo đảm chất lượng.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0477', 'S6.1', 1, 'single_choice', 'Mô hình phân cấp chăm sóc người bệnh dựa trên:', '["Khả năng chi trả", "Mức độ nặng và nhu cầu chăm sóc của người bệnh", "Tuổi tác đơn thuần", "Giới tính"]'::jsonb, 1, 'Phân cấp chăm sóc (cấp I, II, III) dựa trên mức độ nặng và nhu cầu để bố trí nguồn lực điều dưỡng phù hợp.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0478', 'S6.1', 2, 'single_choice', 'Chăm sóc người bệnh toàn diện nhấn mạnh:', '["Chỉ thực hiện y lệnh", "Đáp ứng nhu cầu thể chất, tinh thần và phối hợp liên tục của ĐD", "Chỉ dùng thuốc", "Chỉ vệ sinh"]'::jsonb, 1, 'Chăm sóc toàn diện lấy NB làm trung tâm, đáp ứng nhu cầu thể chất - tinh thần - xã hội, do ĐD chủ động và phối hợp thực hiện.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0479', 'S6.1', 1, 'single_choice', 'Nhiệm vụ của điều dưỡng trưởng khoa KHÔNG bao gồm:', '["Tổ chức, phân công chăm sóc", "Chẩn đoán bệnh và kê đơn điều trị", "Giám sát chất lượng chăm sóc", "Quản lý nhân lực ĐD"]'::jsonb, 1, 'ĐD trưởng khoa quản lý, tổ chức, giám sát chăm sóc và nhân lực ĐD; chẩn đoán và kê đơn thuộc bác sĩ.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0480', 'S6.1', 3, 'single_choice', 'Ghi chép hồ sơ chăm sóc điều dưỡng có ý nghĩa:', '["Chỉ thủ tục", "Bằng chứng chăm sóc, cơ sở pháp lý và phục vụ liên tục điều trị", "Không cần thiết", "Chỉ để lưu trữ"]'::jsonb, 1, 'Hồ sơ điều dưỡng là bằng chứng hoạt động chăm sóc, cơ sở pháp lý, hỗ trợ giao tiếp nhóm và bảo đảm liên tục điều trị.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0481', 'S6.1', 2, 'single_choice', 'Bảo đảm an toàn người bệnh là trách nhiệm của:', '["Chỉ điều dưỡng", "Toàn hệ thống và mọi nhân viên y tế", "Chỉ bác sĩ", "Chỉ lãnh đạo"]'::jsonb, 1, 'An toàn người bệnh là trách nhiệm chung của cả hệ thống; mỗi nhân viên đều tham gia phòng ngừa sự cố và cải tiến chất lượng.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0482', 'S6.2', 1, 'single_choice', 'Kíp gây mê hồi sức tối thiểu cho một cuộc mổ thường gồm:', '["Chỉ phẫu thuật viên", "Bác sĩ gây mê và điều dưỡng/kỹ thuật viên phụ mê", "Chỉ điều dưỡng", "Chỉ hộ lý"]'::jsonb, 1, 'Bảo đảm an toàn gây mê cần bác sĩ gây mê chịu trách nhiệm chuyên môn và ĐD/KTV phụ mê hỗ trợ theo dõi.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0483', 'S6.2', 2, 'single_choice', 'Đánh giá NB trước gây mê (khám tiền mê) nhằm:', '["Thủ tục hành chính", "Phân loại nguy cơ, tối ưu tình trạng NB và lập kế hoạch gây mê", "Tính viện phí", "Chọn phòng"]'::jsonb, 1, 'Khám tiền mê giúp đánh giá nguy cơ (ASA), phát hiện bệnh nền, tối ưu hóa NB và lập kế hoạch gây mê an toàn.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0484', 'S6.2', 1, 'single_choice', 'Phân loại ASA dùng để:', '["Đo huyết áp", "Đánh giá tình trạng thể chất/nguy cơ trước gây mê", "Định nhóm máu", "Đo đường huyết"]'::jsonb, 1, 'Phân loại ASA (I-VI) đánh giá tình trạng thể chất và nguy cơ chu phẫu của người bệnh trước gây mê.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0485', 'S6.2', 2, 'single_choice', 'Bàn giao NB từ phòng mổ về khoa/hồi sức cần chuyển giao thông tin về:', '["Chỉ tên NB", "Diễn biến gây mê - phẫu thuật, thuốc đã dùng, dịch, máu và y lệnh theo dõi", "Chỉ chẩn đoán", "Không cần bàn giao"]'::jsonb, 1, 'Bàn giao sau mổ phải nêu diễn biến gây mê - phẫu thuật, lượng máu/dịch, thuốc đã dùng và kế hoạch theo dõi/điều trị tiếp.', '', ARRAY['VB08','CS05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0486', 'S6.2', 3, 'single_choice', 'Kiểm tra và bảo dưỡng định kỳ máy gây mê, monitor nhằm:', '["Hình thức", "Bảo đảm thiết bị hoạt động chính xác, an toàn cho NB", "Tăng tuổi thọ máy đơn thuần", "Giảm chi phí điện"]'::jsonb, 1, 'Bảo dưỡng, hiệu chuẩn và kiểm tra định kỳ thiết bị gây mê - theo dõi giúp phát hiện lỗi, bảo đảm số liệu chính xác và an toàn.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0487', 'S6.2', 2, 'single_choice', 'Quản lý thuốc gây mê, thuốc hướng thần và thuốc gây nghiện trong khoa GMHS phải:', '["Để chung tủ thường", "Quản lý, cấp phát và ghi chép chặt chẽ theo quy định", "Ai cũng dùng được", "Không cần sổ sách"]'::jsonb, 1, 'Thuốc gây nghiện/hướng thần đòi hỏi bảo quản riêng, sổ theo dõi, cấp phát và bàn giao chặt chẽ theo quy chế dược.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0488', 'S6.3', 1, 'single_choice', 'Bảng kiểm (checklist) đánh giá thực hành có mục đích:', '["Xếp loại thi đua đơn thuần", "Chuẩn hóa quy trình, bảo đảm không bỏ sót bước quan trọng", "Thay thế đào tạo", "Trang trí hồ sơ"]'::jsonb, 1, 'Bảng kiểm giúp chuẩn hóa các bước, đánh giá khách quan năng lực thực hành và bảo đảm không bỏ sót bước quan trọng.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0489', 'S6.3', 2, 'single_choice', 'Ưu điểm của đánh giá dựa trên bảng kiểm so với đánh giá cảm tính là:', '["Nhanh hơn", "Khách quan, nhất quán và có thể tái lập giữa các người đánh giá", "Không cần đào tạo", "Không cần quan sát"]'::jsonb, 1, 'Bảng kiểm cung cấp tiêu chí rõ ràng, giúp đánh giá khách quan, nhất quán và tái lập giữa các đánh giá viên.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0490', 'S6.3', 1, 'single_choice', 'Khi chấm bảng kiểm kỹ năng, người đánh giá nên:', '["Đánh giá theo trí nhớ", "Quan sát trực tiếp và đối chiếu từng bước theo tiêu chí", "Hỏi đồng nghiệp", "Chấm ngẫu nhiên"]'::jsonb, 1, 'Đánh giá kỹ năng cần quan sát trực tiếp thao tác và đối chiếu từng bước với tiêu chí trong bảng kiểm.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0491', 'S6.3', 2, 'single_choice', 'Phản hồi (feedback) sau đánh giá thực hành nên:', '["Chỉ nêu lỗi", "Cụ thể, mang tính xây dựng, chỉ ra điểm mạnh và điểm cần cải thiện", "Chung chung", "Không cần phản hồi"]'::jsonb, 1, 'Phản hồi hiệu quả cần cụ thể, kịp thời, xây dựng — ghi nhận điểm mạnh và hướng dẫn cải thiện điểm yếu.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0492', 'S6.3', 3, 'single_choice', 'Đánh giá năng lực thực hành lâm sàng nên kết hợp nhiều phương pháp vì:', '["Cho phức tạp", "Tăng độ tin cậy và phản ánh đầy đủ kiến thức - kỹ năng - thái độ", "Tốn thời gian", "Theo phong trào"]'::jsonb, 1, 'Kết hợp trắc nghiệm, quan sát bảng kiểm, tình huống (OSCE)... phản ánh toàn diện năng lực và tăng độ tin cậy của đánh giá.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0493', 'S6.3', 1, 'single_choice', 'Chu trình cải tiến chất lượng thường dùng trong y tế là:', '["SWOT", "PDCA (Plan-Do-Check-Act)", "SBAR", "ABCDE"]'::jsonb, 1, 'PDCA (Lập kế hoạch - Thực hiện - Kiểm tra - Hành động) là chu trình cải tiến chất lượng liên tục phổ biến trong y tế.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0494', 'S3.1', 2, 'single_choice', 'Nhóm máu Rh(D) dương tính nghĩa là hồng cầu:', '["Không có kháng nguyên D", "Có kháng nguyên D trên bề mặt", "Có kháng thể kháng D", "Thuộc nhóm O"]'::jsonb, 1, 'Rh(D) dương tính khi hồng cầu mang kháng nguyên D; người Rh âm không có kháng nguyên D và có thể sinh kháng thể kháng D khi phơi nhiễm.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0495', 'S2.1', 1, 'single_choice', 'Xác nhận NB đã ký cam kết và nhịn ăn đủ giờ thuộc bước nào của bảng kiểm an toàn phẫu thuật?', '["Sign out", "Sign in (trước khởi mê)", "Time out", "Sau mổ"]'::jsonb, 1, 'Bước Sign in (trước khởi mê) kiểm tra định danh, cam kết, vị trí mổ, dị ứng, đường thở và nhịn ăn.', '', ARRAY['CS01','VB10'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0496', 'S4.1', 1, 'single_choice', 'Vệ sinh tay thường quy bằng dung dịch chứa cồn cần chà tối thiểu khoảng:', '["3 giây", "20-30 giây cho đến khi tay khô", "2 phút", "Không cần thời gian"]'::jsonb, 1, 'Chà tay bằng dung dịch cồn khoảng 20-30 giây phủ đều mọi bề mặt đến khi khô mới đạt hiệu quả khử khuẩn.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0497', 'S5.1', 1, 'single_choice', 'Vị trí đặt tay ép tim ngoài lồng ngực cho người lớn là:', '["Vùng thượng vị", "Nửa dưới xương ức, giữa lồng ngực", "Mỏm tim bên trái", "Vùng cổ"]'::jsonb, 1, 'Đặt gót bàn tay ở nửa dưới xương ức (giữa ngực) để ép tim hiệu quả và tránh tổn thương tạng.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0498', 'S5.3', 2, 'single_choice', 'Người bệnh sau gây tê tủy sống bị tụt huyết áp, nguyên nhân thường do:', '["Tăng thể tích", "Giãn mạch do ức chế giao cảm", "Sốt cao", "Đau"]'::jsonb, 1, 'Gây tê tủy sống ức chế giao cảm gây giãn mạch, tụt huyết áp; xử trí bằng bù dịch, tư thế và thuốc co mạch theo y lệnh.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0499', 'S3.8', 2, 'single_choice', 'Sau khi đặt nội khí quản, cần cố định ống và ghi lại:', '["Chỉ giờ đặt", "Độ sâu ống (vạch cm ở cung răng) để phát hiện tuột/di lệch", "Màu ống", "Hãng sản xuất"]'::jsonb, 1, 'Ghi và theo dõi độ sâu ống ở mốc cung răng giúp phát hiện sớm ống bị tuột ra hoặc tụt sâu một bên.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0500', 'S6.3', 1, 'single_choice', 'Tần suất đánh giá lại năng lực thực hành của nhân viên nên:', '["Chỉ một lần khi tuyển", "Định kỳ và khi có quy trình/kỹ thuật mới", "Không cần đánh giá lại", "Chỉ khi có sự cố"]'::jsonb, 1, 'Đánh giá năng lực nên thực hiện định kỳ và mỗi khi có kỹ thuật/quy trình mới để duy trì và cập nhật năng lực hành nghề.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
